#!/usr/bin/env bash
# topic-2.sh — 良率 决策助手 for 半导体芯片制造工艺.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="半导体芯片制造工艺"
TOPIC="良率"

usage() {
  cat <<EOF
topic-2.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 3 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-2.sh             # interactive
  ./topic-2.sh --dry-run   # walk through but no file
  ./topic-2.sh --json      # JSON to stdout
  ./topic-2.sh --explain   # show backing playbook rules + mental models
  ./topic-2.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 良率 主题下的 playbook 规则组合成交互树。

基于 3 条规则:
  • 如果 要判断一条产线 / 一个「国产突破」声称能否做某节点 → 则 逐一核验设备 + 材料 + 刻蚀沉积 + 工艺整合 + 良率五要素是否齐备，别只看有没有光刻机 / EUV。案例：SMI
  • 如果 出现良率 / 参数差异 → 则 先做 commonality（设备/层/时间/腔体共性）+ wafer map 空间签名定位到工艺源，再深挖根因，不全检
  • 如果 选先进光刻分解策略 → 则 在 high-NA EUV 单次曝光 vs DUV 多重曝光（SADP/SAQP）间按 pitch 临界点 + 成本/良

相关心智模型:
  • 物理硬约束 ⇄ 良率/成本经济约束（第一性双重张力）: 半导体工艺的每个决策都同时受两类硬约束——物理/化学/材料（量子隧穿、短沟道效应、RC 延迟、热预算、缺陷物理）与良率/成本经济（D0 缺陷密度、每片晶圆成本、wph、折旧）；摩尔定律首先是**经济命
  • 设备/工艺是必要非充分，良率 know-how 才是真壁垒: 能不能做先进制程，从来不是「有没有 EUV/光刻机」单一决定的——设备 + 材料 + 刻蚀/沉积 + 工艺整合 + 良率爬坡**五要素缺一不可**，而良率 ramp 的 know-how 是 silo

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "要判断一条产线 / 一个「国产突破」声称能否做某节点"
  "出现良率 / 参数差异"
  "选先进光刻分解策略"
)
declare -a RULE_ACTIONS=(
  "逐一核验设备 + 材料 + 刻蚀沉积 + 工艺整合 + 良率五要素是否齐备，别只看有没有光刻机 / EUV。案例：SMIC 拆解显示无 EUV 也能做 N+2，但良率/成本/成熟度仍落后数年（业内估计）。evidence: [T01-S017, T02-S029]"
  "先做 commonality（设备/层/时间/腔体共性）+ wafer map 空间签名定位到工艺源，再深挖根因，不全检穷举。案例：先进节点系统性良率问题用 Pareto/commonality 逐层定位再 FA（T03-S001）。evidence: [T03-S001, T03-S002]"
  "在 high-NA EUV 单次曝光 vs DUV 多重曝光（SADP/SAQP）间按 pitch 临界点 + 成本/良率权衡，单曝省步但设备极贵。案例：high-NA 单次曝光可替代部分 SADP/SAQP 的多步流程（T03-S011）。evidence: [T03-S011, T06-S010]"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-2-decision"
fi
